signal(SIGPIPE, SIG_IGN);

if (opt->role == DS4_DISTRIBUTED_COORDINATOR) {
    return dist_run_coordinator(engine, opt, gen);
}
if (opt->role == DS4_DISTRIBUTED_WORKER) {
    return dist_run_worker(engine, opt, gen ? gen->ctx_size : 0);
}

